INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (201, NULL, NULL, 'IndiferenteVirreinal,caja4156,exp025', 'Expediente 025 (Real Audiencia Caja 4156)', 'Petición del Gobernador, Alcaldes y Regidores del pueblo de Pazoyuca para que sean sacados unos indios que entraron en las minas de Pachuca del Real Monte y que ayudan a los religiosos a celebrar los divinos oficios por que estan distrayendo a los mineros.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (202, NULL, NULL, 'IndiferenteVirreinal,caja5419,exp074', 'Expediente 074 (Alcaldes Mayores Caja 5419)', 'Prevención de la alcaldía mayor de Zempoala para la dección de ella y recaudación de sus tributos, persona de calidad, concurriendo a Dn. Joseph Dorantes, elegido y nombrado alcalde mayor.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (203, NULL, NULL, 'Indios,v2,exp694', 'Expediente 694', 'PARA QUE GASPAR DE MORONES, TENIENTE DE CORREGIDOR DE ZEMPOALA, NO LLEVE INDIOS A TRABAJAR A SUS GRANJERIAS. HIDALGO. Po. EPAZOYUCA.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (204, NULL, NULL, 'Indios,v2,exp697', 'Expediente 697', 'ORDENANDO AL TENIENTE GASPAR DE MORONES, QUE VIVE EN ZEMPOALA, NO SAQUE A LOS NATURALES DEL PUEBLO DE EPAZOYUCA. HIDALGO. Po. EPAZOYUCA.
