INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (207, NULL, NULL, 'Indios,v2,exp835', 'Expediente 835', 'PARA QUE SE GUARDE POR EL CORREGIDOR EL MANDAMIENTO RELATIVO A QUE NO OCUPEN CASAS DE COMUNIDAD DE LOS NATURALES DE ZACUALA PARA HABITACION DEL TENIENTE Y CARCEL. HIDALGO. Po. ZEMPOALA.
