INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (210, NULL, NULL, 'Indios,v3,exp171', 'Expediente 171', 'ORDENANDO AL CORREGIDOR DE DICHO PUEBLO NO PERMITA QUE PERSONA ALGUNA ESPANTE A LOS NATURALES EN LAS CERCANIAS CON ARCABUCES U OTRAS ARMAS. HIDALGO. Po. ZEMPOALA.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (211, NULL, NULL, 'Indios,v5,exp529', 'Expediente 529', 'AL CORREGIDOR DE ZEMPOALA, PARA QUE VAYA A LA PARTE EN QUE DON DIEGO DE LA HORTA PRETENDE EL SITIO DE ESTANCIA Y VEA EL PERJUICIO QUE SE SIGUE A LOS NATURALES DE CONCEDERSE LA MERCED. HIDALGO. Po. SINGUILUCAN.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (212, NULL, NULL, 'Indios,v6.1,exp742', 'Expediente 742', 'AL CORREGIDOR DE OTUMBA, PARA QUE CON VARA DE JUSTICIA ACUDA A LOS PUEBLOS DE ZEMPOALA Y TEPEAPULCO, A FIN DE QUE COMPELA A LOS NATURALES AL REPARO DE LOS PUENTES Y LOS DESAGUADEROS. EDO. DE MEXICO. Po. ZEMPOALA. 1¦ PTE.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (213, NULL, NULL, 'Indios,v11,exp126', 'Expediente 126', 'PARA QUE EL JUEZ REPARTIDOR DE LAS MINAS DE PACHUCA NO PIDA NATURALES PARA LAS MINAS DE LAS OCHO QUE HAN QUEDADO EN SAN JUANICO, JURISDICCION DE ZEMPOALA. JURIS. HIDALGO. PO. SAN JUANICO.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (214, NULL, NULL, 'Indios,v15.2,exp103', 'Expediente 103', 'PARA QUE LA JUSTICIA DE ZEMPOALA AMPARE A PETRONILA RODRIGUEZ EN SUS MAGUEYES PARA QUE EL GOBERNADOR Y ALCALDES NO SE LOS QUITEN. JURIS. HIDALGO. Po. ZEMPOALA.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (215, NULL, NULL, 'Indios,v18,exp40', 'Expediente 40', 'PARA QUE EL CORREGIDOR DE OTUMBA, VAYA AL DE ZEMPOALA Y CONFORME A LAS ELECCIONES CONFIRMADAS POR SU EXCELENCIA, ENTREGUE LAS VARAS DE SUS OFICIOS A LOS NOMBRADOS Y LOS ENTRE EN POSESION DE ELLOS. JURIS. EDO. DE MEXICO. Po. ZEMPOALA.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (216, NULL, NULL, 'Indios,v19,exp49', 'Expediente 49', 'PARA QUE LA JUSTICIA DE ATITALAQUIA NO IMPIDA A LOS NATURALES HACER EL PULQUE BLANCO DE SUS COSECHAS NI VENDERLO A QUIEN SE LOS COMPRARE, EN CONFORMIDAD DE LAS ORDENANZAS. JURIS. HIDALGO. Bo. SANTA MARIA TETLIZTAC.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (217, NULL, NULL, 'Indios,v19,exp354', 'Expediente 354', 'PARA QUE EL PRESENTE CORREGIDOR Y LOS QUE EN ADELANTE LO FUEREN DE ZEMPOALA NO IMPIDAN A JUAN MIGUEL, DEL PUEBLO DE SAN AGUSTIN TOHOTLALCO, TENER SU GANADO Y SEÑALARLO CON SU HIERRO TRAYENDOLO CON GUARDA. Po. SAN AGUSTIN TOHOTLALCO.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (218, NULL, NULL, 'Indios,v20,exp228', 'Expediente 228', 'PARA QUE LA JUSTICIA DEL PARTIDO DE ZEMPOALA, AMPARE EN SUS TIERRAS AL GOBERNADOR Y NATURALES DEL PUEBLO DE EPAZAYUCA DE ESTA JURISDICCION, SIN LUGAR A QUE QUEDEN AGRAVIADOS. JURIS. HIDALGO. Po. EPAZAYUCA.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (219, NULL, NULL, 'Indios,v21,exp95', 'Expediente 95', 'SU EXCELENCIA MANDA SE DE TRASLADO A JOSE DE ALVARADO, FRANCISCO DE SOLIS, JUAN BAUTISTA, INDIOS NATURALES, DEL PUEBLO DE SAN AGUSTIN TENANGO, SOBRE LAS ACUSACIONES QUE LES HACEN EL CABILDO Y NATURALES DEL PUEBLO DE TUTUTEPEQUE, SU CABECERA, DE INSURRECCION CONTRA LA JUSTICIA Y DOCTRINA; QUE EL CORREGIDOR DE ZEMPOALA ABSUELVA Y DE POR LIBRES A LOS NATURALES QUE TIENE PRESOS. JURIS. HIDALGO. Po. TUTUTEPEQUE.
