INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (509, 11, NULL, 'JGI_XXV-04_Teguantepec', 'Relación de Teguantepec', 'Description of Teguantepec and several other towns located in the Diocese of Oaxaca. Signers of the census are Juan de Torre de Lagunas, Diego de Alcalá, Andrés López, and Diego Ruiz de Andrada. Details list Zapoteca, Mixteca, and Mexicana as languages spoken, etymology of place names, systems of governance, fauna, and monasteries and convents. Also included are topographic features and the communities of Xalapa, Tequantepec, Santuin, Nustequilla, Hiulotepec, Suchitlom, Yztactepec Coba, Conitlom, Hacotepec, Petapa, Siltepec, Decetun, and Petchitlan. Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (511, 11, NULL, 'JGI_XXV-09_Zacatula', 'Relación de Zacatula', 'Description of Zacatula, located in the Diocese of Michoacan. Census was signed by Diego de Ortega and Juan Ruiz de Mendoza. Document lists many languages including Mexicana as the spoken languages. The document begins with correspondence from Hernando de Vascones to Lorenzo Suárez de Mendoza dated 1581, as well as another letter signed by Hernando de Vascones and his scribe Andrés de Zebreros dated 1580. Document also describes the climate, local jurisdiction, local hierarchy and systems of governance, topographic features, flora and fauna, medicines used, local sanitation methods, and port capacity. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (512, 11, NULL, 'JGI_XXV-12_Tetlistaca', 'Relación de Tetlistaca', 'Description of Tetlistaca, town in the Archdiocese of Mexico. Census signed by Luis de Obregón. Description lists Mexicana as the spoken language, topographic features, and flora and fauna. There are also descriptions of the etymology of names, local hierarchy and systems of governance.  Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (513, 11, NULL, 'JGI_XXIV-09_Iztepec', 'Relación de Iztepec', 'Description of the administrative capital of Iztepec located in the Diocese of Oaxaca. Census was signed by Fray Andrés Méndez. Document describes Iztepec and its surrounding communities with details of their history, etymology of place names, geographic location, natural resources, flora and fauna, clothing, trading partners, and other information. Zapoteca is listed as the spoken language. Smaller communities mentioned include Santa Ana Tacolabacoya, Ayocuexco, San Bernardo, and Santa María Magdalena Tepecimatlan. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (514, 11, NULL, 'JGI_XXIII-09_Amula', 'Relación de Amula', 'Description of Zapotitlan located in the province of Amula, Diocese of Guadalajara. Also included are full descriptions of Tuscacuesco and Cusalapa. Census was signed by alcalde mayor Francisco de Agüero. Document details the history of the province of Amula, lists Mexicana and Otomí as the languages spoken, topographic features, as well as systems of governance and local hierarchies.  This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (515, 11, NULL, 'JGI-XXV-10_Cempoala', 'Relación de Cempoala', 'Description of Cempoala and surrounding towns located in the Archdiocese of Mexico. Census was signed by Luis de Obregón. Document details Cempoala''s local jurisdiction, etymology of names, systems of governances, and local hierarchy and customs. Three other cabeceras are mentioned: Tlaquilpa, Tzaquala, and Tecpupan. Additionally, the census lists Mexicana as the spoken language, churches and hospitals. Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (603, 13, NULL, 'AGI_GUADALAJARA_5_R1_N5', 'Carta de Francisco Vázquez Coronado, juez de comisión, para tomar residencia al licenciado [Diego] de la Torre.', NULL, NULL);
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (613, 2, NULL, 'AGN_RealesCedDup_v029_exp359-360', NULL, NULL, NULL);
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (517, 11, NULL, 'JGI_XXV-03_TeozacoalcoAmoltepec', 'Relación de Teozacoalco y Amoltepec', 'Description of Teozacoalco and Amoltepec, towns in the Diocese of Oaxaca. Census signed by Juan Ruiz Zuazo and Hernando de Cervantes. Document lists Mixteca as the spoken language, surrounding towns such as Zenzontepeque, topographic features, and flora and fauna. There are also details of the local jurisdiction, hierarchy, and systems of governance, etymology of names,  and churches. Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (518, 11, NULL, 'JGI_XXIV-13_Misantla', 'Relación de Misantla', 'Description of Misantla, town in the Diocese of Tlaxcala. Census signed by Diego Pérez de Arteaga. Document lists Totonaco as the spoken language, flora and fauna, and surrounding towns such as Colipa, Mezcalizingo, and Chiconquiaco. There are also details of the native population, topographic features, etymology of names, local hierarchy and systems of governance, and medicines used.  Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (519, 11, NULL, 'JGI_XXIV-04_Cuautla', 'Relación de Cuautla', 'Description of the administrative capital of Cuautla and full descriptions of its surrounding communities named Xocoticpaque, Xaltepetongo, Tututepetongo, and Tanatepec in the Diocese of Oaxaca. Census was signed by Mélchior Suárez. Document lists Mixteca and Cuicateca as the spoken languages, local hierarchies, systems of governance, and fauna. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (520, 11, NULL, 'JGI_XXV-08_laVeracruz', 'Relación de la Veracruz', 'Description of la Veracruz located in the Diocese of Tlaxcala. Census is signed by Bachiller licensed medic Alonso Hernández Diosdado. Description lists Mexicana as the spoken language, discoverer of the province, location of churches, topographic features and their names. The document also describes the climate, fauna, the native population, health of the land, hospitals, medicinal practices, and port capacity. Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (521, 11, NULL, 'JGI_XXIII-12_AtengoMisquiahuala', 'Relación de Atengo y Misquiahuala', 'Description of Atengo and Misquiahuala located in the Archdiocese of Mexico. Census signed by Pedro Franco. Document details Otomí as the language spoken, etymology of its names, church locations, and topographic features. Additionally, there are descriptions of each town''s natural resources, hospitals and schools. Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (522, 11, NULL, 'JGI_XXV-05_Tequixquiac', 'Relación de Tequixquiac', 'Description of Tequixquiac, located in the Archdiocese of Mexico. Census is signed by Alonso de Galdo. Document lists Otomí and Mexicana as the spoken languages, surrounding towns such as Tepexi, Quauhtitlan, Hueypustla, Atitalaquia, Xilolzingo, Atotonilco, Citlaltepec. Also mentioned are details of the local jurisdiction, hierarchy, and systems of governance, topographic features, medicines used, fauna, etymology of names, and farms. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (523, 11, NULL, 'JGI_XXIII-14_Culhuacan', 'Relación de Culhuacan', 'Description of Culhuacan, town in the Archdiocese of Mexico. Census was signed by Gonzalo Gallegos and Fray Juan Núñez. Document lists Mexicaltzingo as the cabecera, Mexicana as the language spoken, natural resources, and fauna. There are also descriptions of systems of governance, the native population, topographic features, and architecture. Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (524, 11, NULL, 'JGI_XXIV-10_Cuylapa', 'Relación de Cuylapa', 'Description of Cuylapa, Diocese of Oaxaca. Census was signed by Fray Agustín de Salazar. Document lists Mixteca as a spoken language, etymology of place names, and 16 estancias and small towns. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (525, 11, NULL, 'JGI_XXV-06_Tetiquipa', 'Relación de Tetiquipa y Cozautepec', 'Description of Tetiquipa and Cozautepec, towns located in the Diocese of Oaxaca. Census is signed by Cristóbal de Salas. Document lists Mixteca and Zapoteca as the spoken languages, flora and fauna, and medicines used. Mentions the sixteen towns under the governance of Tetiquipa and Cozutepec''s geographical positioning related to Tetiquipa and the Puerto de Guatulco. Also mentioned are descriptions of the native population, local jurisdiction, hierarchy, systems of governance, and etymology of names. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (614, 2, NULL, 'AGN_RealesCedDup_v029_exp424-427', NULL, NULL, NULL);
