INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (528, 11, NULL, 'JGI_XXIV-08_Iztapalapa', 'Relación de Iztapalapa', 'Description of Iztapalapa, town subject to Mexicaltzingo in the Archdiocese of Mexico. Census was signed by Dr. Francisco de Loya. Document lists Mexicana as the spoken language, surrounding towns such as Xuckimilco and Cuitlahuac, and flora and fauna. There are also details of topographic features, local jurisdiction, hierarchy and systems of governance, and monasteries and convents.  Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (530, 11, NULL, 'JGI_XXIV-03_Huaxtepeque', 'Relación de Huaxtepeque', 'Description of Huaxtepeque, town in the Archdiocese of Mexico. Census was signed by alcalde mayor Juan Gutiérrez de Liébana. Document lists Mexicana as the language spoken, surrounding towns such as Yauhtepeque and Tlayacapana, and flora and fauna. There are also details of the local jurisdiction, medicines used, topographic features, local hierarchy, systems of governance, etymology of names,  Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (531, 11, NULL, 'JGI_XXIV-02_Coatzacualco', 'Relación de Coatzacualco', 'Description of the province of Coatzacualco, which includes the town of Espíritu Santo and other adjacent towns in the Diocese of Oaxaca. Census was signed by alcalde mayor Suero de Cangas y Quiñonez. Document lists Mexicana, Mixteca, Zapotexa, and Popoluca as spoken languages, and over sixty towns. Additionally mentioned are, topographic features, natural resources, hospitals, churches, local hierarchy, and customs.  Also included is a visual representation of the landscape, known as a pintura or map, which maps the course of the Coatzacualco River and the towns on its banks. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (532, 11, NULL, 'JGI_XXIV-16_QuatlatlaucaGueguetlan', 'Relación de Quatlatlauca y Gueguetlan', 'Description of Quatlatlauca and Gueguetlan, towns in the Diocese of Tlaxcala. Census signed by Fray Juan Miguélez, Fray Agustín de Aranda, and Antonio de Vargas. Document lists Mexicana as the spoken language, topographic features, and flora and fauna. There are also details of the native population and the monasteries and convents. Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (533, 11, NULL, 'JGI_XXIII-13_Atlatlauhca', 'Relación de Atlatlauhca', 'Description of Atlatlauhca and surrounding towns located in the Archdiocese of Mexico. Census was signed by Gaspar de Solís. Responses describe Mexicana and Matlatzinca as the languages spoken, local hierarchy, topographic features and etymology of its name. Also included are the surrounding communities of Villa de Toluca, Teutenango, Suchiaca, Mactexa, Calimaya, and Tepemaxalco. Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (534, 11, NULL, 'JGI_XXV-11_Epazoyuca', 'Relación de Epazoyuca', 'Description of Epazoyuca, located in the Archdiocese of Mexico. Census was signed by Luis de Obregón. Document lists Mexicana as the spoken language and surrounding towns such as Tzihuiquiluca, Tetliztaca, Tepeapulco, Cempoala. There are also details about the local jurisdiction, local hierarchy, systems of governance, etymology of names, and fauna.  Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (535, 11, NULL, 'JGI_XXV-13_TistlaMuchitlan', 'Relación de Tistla y Muchitlan', 'Description of Tistla and Muchitlan, towns near the Mines of Zumpango and in the Diocese of Tlaxcala. Census was signed by Gonzalo Bazán the Alcalde Mayor, and Francisco Martínez. Document lists Matlatzinca, Mexicana, and Tuzteco as the spoken languages, topographic features, medicines used, and flora and fauna. There are also descriptions of the native population, local jurisdiction, hierarchy, and systems of governance, etymology of names, farms, hospitals, and monasteries and convents. Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (537, 11, NULL, 'JGI_XII-16_Texcoco', 'Relación de la Ciudad de Tezcoco', '19th century copy of a description of Texcoco, located in the Archdiocese of Mexico. Signer of the original 1582 work is Juan Bautista de Pomar. Document lists Chichimeca, Mexicana, and Otomí as the spoken languages, surrounding towns such as Chiauhtlacae, Tetzoyucan, and Cohuatlichancomo, topographic features, medicines used, and flora and fauna. Also mentioned are descriptions of the local jurisdiction, hierarchy, systems of governance, etymology of names, and architecture. This is a copy of one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585. This 19th century copy is one of two existing copies of Pomar''s Relación de Texcoco, with the other also being found in this repository. It is a 17th century copy titled "Relación de Tezcuco" and is classified as García MSS 58-57. Bibliophile Ignacio Rayón along with the collector Joaquín García Icazbalceta, utilized the 17th century copy, which at the time was located at the library of the Colegio de San Gregorio in Mexico City, to create this 19th century copy.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (538, 11, NULL, 'JGI_XXIV-15_losPenoles', 'Relación de los Peñoles', 'Description of los Peñoles, towns in the Diocese of Oaxaca. Towns included are Itzcuintepéc, Eztitla, Quauxoloticpac, Huiztepec, Totomachapa, and Elotepec. Census was signed by corregidor Diosdado Treviño and Juan López de Zárate. Document lists Mixteca and Zapoteca as the spoken languages, topographic features, flora and fauna, and other natural resources. There are also descriptions of the local hierarchy and systems of governance, etymology of names, and medicines used. Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (539, 11, NULL, 'JGI_XXIII-11_Antequera', 'Relación de Antequera', 'Description of Antequera located in the Diocese of Oaxaca. Census signed by priest clergyman, Pedro Franco, and mayor Pedro de Ledesma. Document details the spoken languages of Mexicana, Zapoteca, and Mixteca. Also mentioned are topographic features, natural resources, and locations of churches and monasteries. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (540, 11, NULL, 'JGI_XXIII-15_Cuzcatlan', 'Relación de Cuzcatlan', 'Description of Cuzcatlan located in the Diocese of Tlaxcala. Census was signed by Juan de Castañeda León. Document lists Chocho, Mazateca, and Mexicana as languages spoken, estancias, locations of churches, topographic features, and flora. Also mentioned are fauna and a description of the native population. Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (541, 11, NULL, 'JGI_XXIV-06_Iguala', 'Relación de Iguala', 'Description of Iguala, located in the Archdiocese of Mexico. The only visible signature is that of the scribe, Fernando Alfonso de Estrada. Document lists Cuixca and Chontal as the spoken languages. Document also details the native population, wildlife, climate, the province, and full descriptions of the region''s cabeceras: Iguala, Cocula, Tepecuacuilco, Mayanala, Ohuapa, Tasmalaca, and Izuco. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (542, 11, NULL, 'JGI_XXIV-14_Patzcuaro', 'Relación de Patzcuaro', 'Description of Patzcuaro, located in the Diocese of Michoacan. Document lists Tarasca as the spoken language, natural resources, and fauna. There are also details of etymology of names, local hierarchy and systems of governance, and hospitals. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (543, 11, NULL, 'JGI_XX-10_Santiago_Atitlan', 'Relación de Santiago Atitlan', 'Description of Santiago Atitlan, located in the Diocese of Guatemala, as well as full descriptions of its estancias named San Bartolomé, San Andrés and San Francisco. Census is signed by Alonso Páez Betancor. Document lists Mexicana and various Guatemalan languages as the spoken languages, natural resources, medicines used, and monasteries and convents. Document describes the province, climate, topographic features, the native population, local jurisdiction, hierarchy and customs, systems of governance, flora and fauna, and farms. Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (544, 11, NULL, 'JGI_XXIV-07_Ixcatlan', 'Relación de Ixcatlan', 'Description of Ixcatlan, located in the Diocese of Oaxaca. Census was signed by Gonzalo Velázquez de Lara. Document lists Cuicateca, Chochona, and Mexicana as the spoken languages and includes full descriptions of Ixcatlan, Quiotepeque, and Tecomahuaca. Additionally included are descriptions of the relationship between Quiotepec and Tecomahuac,  the climate, native population, local jurisdiction, hierarchy and customs, and flora and fauna. Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (643, 14, NULL, 'Fernandez144-MEX16-EMJ-VAG-CCC', '27. De Diego de San Llorente a su mujer, Luisa Sánchez, en Sevilla', 'Diego de San Llorente solicita a su mujer, Luisa Sánchez, que se reúna con él y le da instrucciones para el viaje.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (666, 14, NULL, 'Fernandez352-MEX16-GHT-JGR-CCC', '164. De Andrea López de Vargas a sus hermanas, Catalina y Ana de Vargas, en Jerez (Cádiz)', 'Andrea López de Vargas lamenta la muerte de su madre y da instrucciones precisas para que sus hermanas, Catalina y Ana de Vargas, se reúnan con ella en América.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (546, 11, NULL, 'JGI_XXIII-10_Ameca', 'Relación de Ameca', 'Description of Ameca, initially located in the Archdiocese of Mexico (now under the   Diocese of Guadalajara). Census was signed by alcalde mayor Pedro de Moras. Document details flora and fauna, locations of churches, estancias, and lists Caxcan and Mexicana as the languages spoken. Additionally mentioned are the surrounding communities of Jayamitla, El Cabezón, and San Martín de Hidalgo.  Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (547, 11, NULL, 'JGI_XXIV-18_Tancitaro', 'Relación de Tancitaro', 'Description of Tancitaro, located in the Diocese of Michoacan. Signer of census is believed to be Sebastián Macarro. Document lists Tarasca and Mexicana as the spoken languages and wildlife. Document also details the province, climate, topographic features, the native population, local jurisdictions, etymology of names, monasteries and convents, and includes full descriptions of the surrounding towns named Tlapalcatepeque and Pinzandaro Arimao, with Tancitaro as the cabecera. Also of note is marginialia throughout the manuscript, which has been added by a second, anonymous scribe. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (548, 11, NULL, 'JGI_XXV-02_Tequaltiche', 'Relación de Tequaltiche', 'Description of Tequaltiche, located in the Diocese of Guadalajara. Census signed by Hernando Gallegos. Document lists Caxan and Mexicana as the spoken languages, and topographic features. Also mentioned are descriptions of the native population, local jurisdiction, hierarchy, and systems of governance, and medicines used. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (549, 11, NULL, 'JGI_XXIV-01_Cholula', 'Relación de Cholula', 'Description of Cholula and surrounding towns located in the Diocese of Tlaxcala. Census signed by Gabriel de Rojas. Responses describe locations of churches, lists Mexicana as the language spoken, topographic features including roads leading to Acapetlahuacan, Tlaxcallan, Mexico, Angeles, and Uexotzinco. Additionally, the document describes etymology of names, fauna, local hierarchy and customs. Also included is a visual representation of the landscape, known as a pintura or map. This is one of a series of responses to a political and cultural survey circulated by King Philip II of Spain titled relaciones geográficas, which were gathered between the years 1579-1585.
