INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (601, 13, NULL, 'AGI_GUADALAJARA_230_L2_F.45V-46V', 'Construcción del puente sobre el río Grande y otros asuntos', NULL, NULL);
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (621, 4, NULL, 'AGI_CONTRATACION_1183_N8', 'Registro del navío: ''''San Antonio de Padua''''', 'Registro de ida del navío ''San Antonio de Padua, de ciento ochenta toneladas, maestre Juan Idíaquez, que salió de Cádiz, con la Flota de Roque Centeno y Ordóñez, para Nueva España.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (622, 4, NULL, 'AGI_CONTRATACION_1161_N1_R3', 'Registro del navío: ''''Santa Ana''''', NULL, NULL);
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (623, 4, NULL, 'AGI_CONTRATACION_1089_N8', 'Registro del navío: ''''Santa Ana y Santa Catalina''''', NULL, NULL);
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (624, 4, NULL, 'AGI_CONTRATACION_1091_N3', 'Registro del navío: ''''Nuestra Señora de la Victoria''''', NULL, NULL);
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (625, 4, NULL, 'AGI_CONTRATACION_1091_N10', 'Registro del navío: ''''Nuestra Señora del Socorro''''', NULL, NULL);
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (626, 4, NULL, 'AGI_INDIFERENTE_2065_N45', 'Pedro de Allo', 'Expediente de concesión de licencia para llevar a la Nueva España un barco en compañia de la nao ''San Nicolás'' del capitán y maestre Pedro de Allo.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (628, 4, NULL, 'AGI_CONTRATACION_490_N1_R18', 'Bienes de difuntos: Baltasar de Baeza y otro', 'Autos sobre los bienes de Baltasar de Baeza y Juan de Reina, zapatero, que se ahogaron en la saetía que naufragó en la costa de Tabasco, maestre Diego Rodríguez, vecino de Sevilla.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (629, 4, NULL, 'AGI_CONTRATACION_1090_N1', 'Registro del navío: ''''Nuestra Señora del Rosario''''', NULL, NULL);
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (630, 14, NULL, 'AGI_INDIFERENTE_2051_N3  DLNECC32-MEX16-EAP-GHT', '420. De Juan Rodríguez Zambrano a Juan Martín del Gajo, cuñado de Juan Zambrano, clérigo, en Fuente del Maestre (Badajoz)', 'Juan Rodríguez Zambrano detalla a Juan Martín del Gajo lo que ha podido averiguar acerca de unas deudas de diferentes personas para lo que le había enviado escrituras y poderes.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (631, 14, NULL, 'AGI_INDIFERENTE_2050_N42  DLNECC40-MEX16-EAP-GHT', '9. De Pedro Sánchez a su mujer, Juana Ramos, en Sevilla, en la colación de San Julián', 'Pedro Sánchez escribe a su mujer, Juana Ramos, con dinero e instrucciones para la realización de su viaje.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (632, 14, NULL, 'AGI_INDIFERENTE_2050_N73  DLNECC42-MEX16-EAP-GHT', '330. De Rodrigo de Prado a su padre, Juan de Aguirre, en Sevilla, ambos nacidos en Soria', 'Rodrigo de Prado responde cartas de su padre, Juan de Aguirre, y le pide que sigan sus instrucciones acerca de su hermana Leonor; aunque estas no aparecen de forma explícita se supone que sus hermanos deben llevar a la hermana a América porque la van a casar allí.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (633, 14, NULL, 'AGI_INDIFERENTE_2053_N56   DLNECC47-MEX16-EAP-GHT', '360. De Diego Díaz Galiano, mercader, a su sobrino, Juan Galiano, oficial de Juan Hurtado, secretario de la audiencia real de Sevilla, de donde es vecino', 'Diego Díaz Galiano, mercader, responde a una carta de su sobrino, Juan Galiano, oficial de secretario de la audiencia real de Sevilla, y lo anima a que viaje con él a América.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (634, 14, NULL, 'AGI_INDIFERENTE_2050_N49   DLNECC48-MEX16-EAP-GHT', '8. De Luis de Illescas, pintor de imaginería, a su mujer, Catalina Gutiérrez, en Jerez de la Frontera, Cádiz', 'Luis de Illescas, pintor de imaginería, escribe a su mujer, Catalina Gutiérrez, solicitándole nuevamente que se reúna con él y contra argumentando las excusas que ella anteriormente le había dado para no hacer el viaje.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (635, 14, NULL, 'AGI_INDIFERENTE_2052_N39   DLNECC70-MEX16-EAP-GHT', '19. De Antonio de Aguilar a su mujer, Juana Delgada, en Sevilla', 'Antonio de Aguilar escribe a su mujer, Juana Delgada, rogándole que se reúna con él y dándole instrucciones para realizar su viaje.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (636, 14, NULL, 'AGI_INDIFERENTE_2052_N30   DLNECC73-MEX16-EAP-GHT', '260. De Francisco de León a su madre, Francisca Díaz, en Sevilla', 'Francisco de León escribe a su madre, Francisca Díaz, en respuesta a una carta suya, le cuenta que debe algún dinero de la compra de 36 mulas y 4 negros pero envía tostones para que los vendan y con ello se vayan todos con él a América.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (637, 14, NULL, 'AGI_INDIFERENTE_2055_N35   DLNECC74-MEX16-EAP-GHT', '429. De Gabriel Ramírez a Bernaldino de Madrid', 'Gabriel Ramírez escribe a Bernaldino de Madrid, contándole que había ido a América a descansar y no deja de trabajar recogiendo la hacienda de Marcos Ortiz.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (638, 14, NULL, 'AGI_INDIFERENTE_2054_N38   DLNECC78-MEX16-GHT-JGR', '20. De Diego de San Llorente, sastre, a su mujer, Luisa Sánchez, en Sevilla, en casa del clérigo', 'Diego de San Llorente, sastre, solicita a su mujer, Luisa Sánchez, que se reúna con él.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (639, 14, NULL, 'AGI_INDIFERENTE_2053_N88   DLNECM23-MEX16-GHT-AVB', '23. De Juan de Palencia a su mujer, Magdalena Jiménez, vecinos de Orihuela (Valencia, según dice el expediente)', 'Juan de Palencia da noticias de su vida a su mujer, Magdalena Jiménez, y le ruega que se reúna con él.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (640, 14, NULL, 'DLNECM30-MEX16-GHT-AVB', '358. De Diego Díaz Galiano, mercader, a su sobrino, Juan Galiano, oficial de Juan Hurtado, secretario de la audiencia real de Sevilla, de donde es vecino', 'Diego Díaz Galiano, mercader, responde a una carta de su sobrino, Juan Galiano, oficial de secretario de la audiencia real de Sevilla, aludiendo a la muerte de su hermana y su madre, motivo por el cual no piensa volver a España sino que le invita a que viaje él a América.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (641, 14, NULL, 'AGI_INDIFERENTE_2054_N146   Fernandez102-MEX16-AVB-GHT-CCC', '359. De Gaspar de la Torre a su sobrino Juan Ruiz, en la ciudad de Palencia', 'Gaspar de la Torre habla a su sobrino Juan Ruiz de la llegada de Gaspar de Hordejón, le envía dinero y le dice que sería buena idea que él también se fuera a América con ellos.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (642, 14, NULL, 'AGI_INDIFERENTE_2053_N53   Fernandez143-MEX16-EMJ-VAG-CCC', '26. De Alonso Moreno Serrano a su mujer, María Vázquez de Morales, en Oliva (Badajoz)', 'Alonso Moreno Serrano solicita a su mujer, María Vázquez de Morales, que se reúna con él y le da instrucciones para el viaje.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (263, 3, NULL, 'Amoxcalli_154', 'Carta geográfica del noreste de Nuevo México 1778', NULL, NULL);
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (645, 14, NULL, 'Fernandez146-MEX16-EMJ-VAG-CCC', '569. De Diego de San Llorente a Antón Sánchez, clérigo, en Sevilla', 'Diego de San Llorente le ruega al clérigo Antón Sánchez que se haga cargo de un dinero que envía, junto con una lista de encargos, para que se lo entregue a su mujer y así pueda trasladarse junto a su hijo hasta Puebla de los Ángeles donde él vive.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (646, 14, NULL, 'Fernandez166-MEX16-EMJ-VAG-CCC', '335. De Segundo Martínez a su padre, Domingo Martínez, platero de plata en Sevilla', 'Segundo Martínez escribe a su padre, Domingo Martínez, platero de plata, dándole instrucciones acerca del equipaje, herramientas, comida, etc., que debe llevar para ir a América.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (647, 14, NULL, 'Fernandez195-MEX16-EMJ-VAG-CCC', '362. De Martín Fernández Cubero a su sobrino, Pedro Hernández Cubero, en Fuentelencina (Guadalajara)', 'Martín Fernández Cubero enumera a su sobrino, Pedro Hernández Cubero, las cartas enviadas y recibidas, dice que es un cobarde por no querer ir a América pero insiste en que se vaya con él y le cuenta detalles de su vida.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (648, 14, NULL, 'Fernandez19-MEX16-AVB-GHT-CCC', '363. De Gaspar de la Torre a su sobrino, Juan Ruiz, en Palencia', 'Gaspar de la Torre escribe a su sobrino, Juan Ruiz, quejándose de la falta de noticias y cartas y le pide que se vaya a América con él, dado que puede hacer el viaje con Gaspar de Hordejón.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (650, 14, NULL, 'Fernandez207-MEX16-EMJ-VAG-CCC', '338. De Bartolomé de Morales, barbero, a su padre, Antón Pérez, barbero, en Sevilla', 'Bartolomé de Morales, barbero, pide a su padre, Antón Pérez, que le envíe a Catalina Davila, seguramente su esposa, pues él ha decidido quedarse en América y también le pide algunos utensilios para ejercer su profesión.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (651, 14, NULL, 'Fernandez20-MEX16-AVB-GHT-CCC', '365. De Gaspar de la Torre a su sobrino Juan Ruiz, en Palencia', 'Gaspar de la Torre explica a su sobrino Juan Ruiz que Gaspar de Hordejón no pudo salir en la anterior flota como había dicho en sus cartas pero que va en la siguiente, le dice que se vaya con él y que anime a la mujer de Gaspar de Hordejón para hacer el viaje.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (652, 14, NULL, 'Fernandez216-MEX16-EMJ-VAG-CCC', '468. De Juan de Cantoral, natural de León, a Juan Morán, su amigo, en Sevilla', 'Juan de Cantoral responde una carta de Juan Morán, le agradece que cuide de sus hermanas, le explica cómo recoger el dinero que le ha enviado y le cuenta sobre su vida.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (653, 14, NULL, 'Fernandez218-MEX16-EMJ-VAG-CCC', '587. De Macario de Anzures, mercader de paños, a su cuñado, Francisco Rodríguez, barbero, en Brihuega (Guadalajara)', 'El mercader Macario Anzures le pide a su cuñado que se vaya con él con toda su familia lo antes posible porque él ni está casado ni tiene hijos, y los quiere dejar como herederos de todas sus posesiones y talleres.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (654, 14, NULL, 'Fernandez260-MEX16-GHT-JGR-CCC', '143. De Inés de Solís a su hermana Ángela de Solís, en Medina del Campo (Valladolid)', 'Inés de Solís escribe a su hermana Ángela de Solís sobre su vida y sobre el descubrimiento de China y le pide que le escriba.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (655, 14, NULL, 'Fernandez266-MEX16-GHT-JGR-CCC', '144. De Tomás de la Plaza, deán de Tlaxcala, a su hermana Leonor Plaza, en Alburquerque (Cáceres)', 'Tomás de la Plaza, deán de Tlaxcala, pide a su hermana Leonor Plaza que le envíe a uno de sus hijos.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (656, 14, NULL, 'Fernandez269-MEX16-GHT-JGR-CCC', '145. De Hernando de Ortega a su hermano Juan de Ortega, en Montemolina, en el Maestrazgo de Santiago', 'Hernando de Ortega pide a su hermano Juan de Ortega que se reúna con él en América.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (657, 14, NULL, 'Fernandez26-MEX16-AVB-GHT-CCC', '146. De Bartolomé Ruiz a su hermana Luisa Hernández, vecina de Sevilla, en San Bernardo', 'Bartolomé Ruiz avisa a su hermana Luisa Hernández que su madre al morir le dejó una hacienda en América que tiene que ir a cobrar y le da instrucciones para realizar el viaje.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (658, 14, NULL, 'Fernandez271-MEX16-GHT-JGR-CCC', '266. De Cristóbal Moreno de Velgara y Andrea López de Vargas a la madre de la segunda, María de Vargas, en Jerez de la Frontera (Cádiz)', 'Cristóbal Moreno de Velgara y Andrea López de Vargas escriben a la madre de la segunda, María de Vargas, en respuesta a una carta suya, comenta las noticias recibidas, da varias nuevas, como el nacimiento de una hija, y pide que su hermano vaya con ellos a América.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (659, 14, NULL, 'Fernandez27-MEX16-AVB-GHT-CCC', '341. De Beatriz de Carvallar a su padre, Lorenzo Martínez de Carvallar, en Fuentes de León (Badajoz)', 'Beatriz de Carvallar se alegra con las cartas de su padre, Lorenzo Martínez de Carvallar, responde a ellas y narra las aventuras que pasó hasta llegar a América y su reciente parto, le desaconseja el viaje a América por las dificultades que conlleva pero le expresa la alegría que le causaría su compañía.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (660, 14, NULL, 'Fernandez308-MEX16-GHT-JGR-CCC', '35. De Alonso Ortiz, curtidor, a Leonor González, su mujer, en Zafra (Badajoz)', 'Alonso Ortiz, curtidor, ruega a su mujer, Leonor González, que se reúna con él.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (661, 14, NULL, 'Fernandez315-MEX16-GHT-JGR-CCC', '366. De Juan de Mendoza a su sobrino, Cristóbal de Ayala, en Colmenar de Ávila', 'Juan de Mendoza se queja a su sobrino, Cristóbal de Ayala, de haberle escrito cinco cartas y no haber obtenido respuesta, sobre todo porque le rogaba que se fuera a América para trabajar con él, le da instrucciones e insiste en que lo haga.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (662, 14, NULL, 'Fernandez322-MEX16-GHT-JGR-CCC', '36. De Alonso Ortiz, curtidor, a Leonor González, su mujer, en Zafra (Badajoz)', 'Alonso Ortiz, curtidor, ruega a su mujer, Leonor González, que se reúna con él y responde a una carta que ella le ha enviado.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (663, 14, NULL, 'Fernandez330-MEX16-GHT-JGR-CCC', '476. Del doctor Céspes de Cárdenas, del Consejo de su Majestad, al bachiller Alonso Bernal, en Oropesa (Toledo o Castellón), aunque el expediente es de su hijo, Pedro López Bernal', 'El doctor Céspes de Cárdenas responde al bachiller Alonso Bernal, le cuenta que es alcalde de la corte, con un canonicato, y corregidor, tiene doble sueldo y por eso le ofrece que se vaya con él y así ayudarle a él y a sus primas.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (664, 14, NULL, 'Fernandez335-MEX16-GHT-JGR-CCC', '38. De Pedro de Aguilera a su mujer, Leonor de Paladines, en Sevilla', 'Pedro de Aguilera expresa a su mujer, Leonor de Paladines, la decepción por no haber viajado ya para reunirse con él y le ruega que lo haga en la siguiente flota, para lo cual le da instrucciones precisas.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (665, 14, NULL, 'Fernandez341-MEX16-GHT-JGR-CCC', '269. Cristóbal Vicente a su madre, Mari González, en Lepe (Huelva)', 'Cristóbal Vicente escribe a su madre, Mari González, una breve carta que envía con su hermano, dándole noticia de su vida y algún dinero.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (668, 14, NULL, 'Fernandez359-MEX16-GHT-JGR-CCC', '271. De Andrea López de Vargas a su madre, en Cádiz', 'Andrea López de Vargas escribe a su madre anunciándole que pronto irán ella y su marido a España y con la carta envía dinero y regalos para sus hermanas.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (669, 14, NULL, 'Fernandez35-MEX16-AVB-GHT-CCC', '492. De Juan Alonso Velázquez a Juan García, en Torrezilla de los Cameros (La Rioja)', 'Juan Alonso Velázquez y un amigo suyo acuerdan el casamiento de una hija del primero y un sobrino del segundo, hijo este último del destinatario de la carta, Juan García, a quien se dirige para que se pueda efectuar el trato.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (670, 14, NULL, 'Fernandez360-MEX16-GHT-JGR-CCC', '493. De Bartolomé Pérez Guillermo a Gregorio Sánchez de Moscoso, vecino de Calzadilla (Extremadura)', 'Bartolomé Pérez Guillermo responde a una carta de Gregorio Sánchez de Moscoso en que le dice que quiere ir a América, le pide además que su hermano pueda irse en su compañía, así como la mujer de un conocido, y le da noticias de su vida.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (671, 14, NULL, 'Fernandez362-MEX16-GHT-JGR-CCC', '573. Del fraile dominico Gabriel de San José, a Fray Domingo de Salazar, en la corte, Madrid', 'Fray Gabriel de San José ruega a fray Diego de Salazar que le envíe dos docenas de religiosos, porque hay muchas muertes entre los frailes, que otros se vuelven a España y que allí hay muy pocos nativos que pretendan tomar el hábito religioso.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (672, 14, NULL, 'Fernandez376-MEX16-GHT-JGR-CCC', '506. De García Rodríguez Pardo, canónigo, a su hermano Pedro Pardo, vecino de Vega de Ruy Ponce', 'García Rodríguez Pardo, canónigo, explica a su hermano Pedro Pardo que le ha escrito hace tiempo y no ha obtenido respuesta y que envió dinero y un poder para que se reunieran con él y que tampoco sabe nada de eso, le cuenta también algunos detalles de su vida.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (673, 14, NULL, 'Fernandez385-MEX16-JGR-VAG-CCC', '592. De María Díaz a su yerno, Pedro Díaz Cuello, marido de Inés Díaz, vecinos de Sevilla.', 'María Díaz le pide a su yerno Pedro Díaz que, si él no puede, por lo menos deje ir a su hija con ella para poder estar juntas y disfrutar de las tierras que ha comprado y que van a ser para ellos.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (674, 14, NULL, 'Fernandez38-MEX16-AVB-GHT-CCC', '44. De Francisco de Vera a su mujer, Leonor del Fisco, en Sevilla', 'Francisco de Vera narra a su mujer, Leonor del Fisco, su llegada a América y el comienzo de su nueva vida y pide a su mujer una prórroga de tres años allí.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (675, 14, NULL, 'Fernandez391-MEX16-JGR-VAG-CCC', '48. Antón Torijano, molinero o batanero, a su mujer, Catalina de Ponçe, vecina de Brihuega (Guadalajara)', 'Antón Torijano, molinero o batanero, ruega a su mujer, Catalina de Ponçe, que se reúna con él en América y le da instrucciones precisas para ello.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (676, 14, NULL, 'Fernandez401-MEX16-JGR-VAG-CCC', '513. De Isabel Durán y Mateo Sánchez a Pedro de Torres, que tiene una tienda, en Madrid', 'Isabel Durán y Mateo Sánchez se quejan al tendero Pedro de Torres de que no les haya escrito después de saber que su esposa había muerto, y le piden que les diga cuánto le deben por las atenciones que tuvo con su familia.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (677, 14, NULL, 'Fernandez407-MEX16-JGR-VAG-CCC', '308. De Francisco Ramírez Brauo a su hija, Isabel Brauo, en Lepe (Huelva)', 'Francisco Ramírez Brauo cuenta a su hija, Isabel Brauo, que ha estado enfermo, se queja de no haber recibido respuesta de su última carta, que iba con dinero y la amenaza con dejar de llamarla hija si no va a América con él porque lo ha arreglado todo para ella.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (679, 14, NULL, 'Fernandez417-MEX16-JGR-VAG-CCC', '517. De García Rodríguez Pardo, canónigo, a su hermano, Pedro Pardo, vecino de Vega de Ruy Ponce.', 'El canónigo García Rodríguez le pide a su hermano Pedro Pardo, de Vega de Ruy Ponce, que le dé noticias de un dinero que le ha enviado y le pide que le mande algún sobrino para que le ayude, aunque no anda demasiado bien de dinero por los muchos gastos y la escasez de diezmos.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (680, 14, NULL, 'Fernandez420-MEX16-JGR-VAG-CCC', '51. De Rafael Rodríguez a su mujer, Isabel de Espinosa, vecina de Sevilla', 'Rafael Rodríguez envía dinero y ruega a su mujer, Isabel de Espinosa, que se reúna con él en América y le da instrucciones precisas para ello.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (681, 14, NULL, 'Fernandez429-MEX16-JGR-VAG-CCC', '541. De Francisco Ramírez Bravo a Juan Cerazo. Son vecinos de Lepe (Huelva)', 'Francisco Ramírez se queja a Juan Cerazo de que no ha recibido cartas suyas ni de su hija, y le habla de su grave enfermedad. Le cuenta el descubrimiento de una gran veta de plata en una mina suya en México que le produce más de mil pesos cada semana. Le envía dinero para que su hija se vaya con él y lleve buena ropa y dos sillones.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (682, 14, NULL, 'Fernandez435-MEX16-JGR-VAG-CCC', '195. Gonzalo de Madalén escribe a su hermano Martín de Madalén, vecino de Guernica (Vizcaya)', 'Gonzalo de Madalén responde a una carta de su hermano, Martín de Madalén, y le pide que le envíe a un sobrino con él.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (683, 14, NULL, 'Fernandez436-MEX16-JGR-VAG-CCC', '54. De Pedro Martín, carpintero, a su mujer, Gregoria Rodríguez, vecina de Sevilla', 'Pedro Martín, carpintero, lamenta que su mujer, Gregoria Rodríguez, no haya venido en la última flota y le da instrucciones para que pueda reunirse con él en América.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (684, 14, NULL, 'Fernandez44-MEX16-AVB-GHT-CCC', '201. Fray Pedro de Aguirre, provincial, a su hermano Martín de Aguirre, en Bilbao', 'Fray Pedro de Aguirre, provincial, responde a una carta previa y da cuenta de su vida en América a su hermano, Martín de Aguirre, excusándose de no volver a España y pidiéndole a cambio que sea él quien vaya a América, pues así le ayudará.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (685, 14, NULL, 'Fernandez463-MEX16-JGR-VAG-CCC', '376. Del bachiller Hernando de Villafranca a su sobrino, Antonio de Villafranca, en Toledo', 'El bachiller Hernando de Villafranca declara a su sobrino, Antonio de Villafranca, haber conocido la muerte de su hermano, por lo que le pide que se vayan él y su hermano a América donde les espera la hacienda que él deja.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (686, 14, NULL, 'Fernandez468-MEX16-JGR-VAG-CCC', '596. De Garci Sánchez de Vañares a Juan Martínez, en Nabalagamella (Segovia)', 'Garci Sánchez escribe a su yerno Juan Martínez animándole para que se vayan a vivir con él, ya que está enfermo y muy anciano y no puede vender las tierras para irse con ellos, sino que prefiere que sean ellos los que las hereden y las cuiden.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (687, 14, NULL, 'Fernandez48-MEX16-AVB-GHT-CCC', '204. Pedro de la Torre a su hermano Bartolomé de la Torre, vecino de Madrid, aunque quizá originario de Sevilla', 'Pedro de la Torre reprocha a su hermano Bartolomé de la Torre la falta de cartas y le asegura que el nuevo virrey podrá ayudarles, por lo que debe viajar para reunirse con él en América.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (690, 14, NULL, 'Fernandez506-MEX16-JGR-VAG-CCC', '65. De Juan Díaz Pacheco a su mujer, Ana García, en Sevilla', 'Juan Díaz Pacheco da instrucciones a su mujer, Ana García, para que se reúna con él en América.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (691, 14, NULL, 'Fernandez513-MEX16-VAG-AVB-CCC', '66. Del alférez Gaspar de los Reyes, natural de Sevilla y escribano real de Indias, a su mujer, Catalina Domínguez, vecina de Cortegana (Huelva)', 'El alférez Gaspar de los Reyes, escribano real de Indias, da noticias a su mujer, Catalina Domínguez, de su llegada a América y de los conocidos que ha encontrado.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (692, 14, NULL, 'Fernandez517-MEX16-VAG-AVB-CCC', '67. De Juan de Avendaño, tesorero de Arequipa y después regidor del Cuzco, a su mujer, Ana de Terán, en casa del doctor Palacios de Terán, en Salamanca, aunque fueron vecinos de Toledo.', 'Juan de Avendaño, tesorero de Arequipa y después regidor del Cuzco, responde a una carta de su mujer, Ana de Terán, y la anima a reunirse con él en América viajando con un primo suyo.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (693, 14, NULL, 'Fernandez51-MEX16-AVB-GHT-CCC', '68. De Hernán García a su mujer, Catalina Núñez, vecina de Sevilla', 'Hernán García intenta convencer a su mujer, Catalina Núñez, para que se reúna con él en América.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (694, 14, NULL, 'Fernandez541-MEX16-VAG-AVB-CCC', '597. De Gil de Villegas a Francisco Hurtado, en La Puebla de Montalbán (Toledo)', 'Gil de Villegas desea a Francisco Hurtado que goce de buena salud y le informa del envío de varias piezas de oro, que describe, y una gran cantidad de ducados para que le mande lo antes posible a su sobrino, al que promete cuidar.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (695, 14, NULL, 'Fernandez54-MEX16-AVB-GHT-CCC', '435. De Antón del Río a Andrés Álvarez, su cuñado, vecino de Brihuega (Guadalajara)', 'Antón del Río responde a una carta de Andrés Álvarez, en que le decía que no había recibido el dinero que le había enviado y le da instrucciones para que haga el viaje a América.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (696, 14, NULL, 'Fernandez554-MEX16-VAG-AVB-CCC', '216. De Alonso Martínez de la Cunza y Arbizu a su hermano Juan Martínez de la Cunza y Arbizu, vecino de Biurrún del Rey (Navarra), aunque la carta va a Pamplona', 'Alonso Martínez de la Cunza y Arbizu cuenta que se ha quedado viudo y solo por lo que pide a su hermano Juan Martínez de la Cunza y Arbizu que le envíe con él a un sobrino, que heredará todo lo suyo.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (697, 14, NULL, 'Fernandez569-MEX16-VAG-AVB-CCC', '218. De María de Carranza a su hermano Hernando de Soto, vecino de Sevilla', 'María de Carranza reprocha a su hermano Hernando de Soto la falta de cartas y le ruega que viaje a América con ella para ayudarlo a no pasar necesidad, para lo cual hace una relación muy precisa de los enseres que debe embarcar.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (698, 14, NULL, 'Fernandez573-MEX16-VAG-AVB-CCC', '219. De Juan Zorrilla de la Concha a su hermano Pedro Zorrilla de la Concha, en Espinosa de los Monteros (Burgos)', 'Juan Zorrilla de la Concha alude a las pérdidas que ha tenido por piratas o naufragios, se alegra por la boda de su hermano Pedro Zorrilla de la Concha, le envía dinero para la nuera de Pedro y aviso a Catalina Ezquerra de la muerte de su marido porque él es su albacea.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (699, 14, NULL, 'Fernandez585-MEX16-VAG-AVB-CCC', '385. De Jerónimo de la Paz a Lucas de la Paz, en Triana (Sevilla), de donde es natural', 'Jerónimo de la Paz dice a su sobrino, Lucas de la Paz, que lo ha enviado a llamar en otras cartas y vuelve a hacerlo en la presente.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (700, 14, NULL, 'Fernandez587-MEX16-VAG-AVB-CCC', '436. De Rodrigo de León a Catalina Hernández Esquerra, en Aguilar (Córdoba)', 'Rodrigo de León informa a Catalina Hernández Esquerra de la muerte de su marido camino de China, le explica que no sabe aún qué ha pasado con sus bienes y le pide que le envíe su testamento y un poder.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (701, 14, NULL, 'Fernandez596-MEX16-VAG-AVB-CCC', '315. El doctor Palacio a su hijo, Diego García de Palacio, en la corte', 'el doctor Palacio acusa recibo de cartas de su hijo, Diego García de Palacio, y le informa que ha escrito a su tío para que lo mande a América.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (702, 14, NULL, 'Fernandez597-MEX16-VAG-AVB-CCC', '234. Del licenciado y clérigo Rodrigo de Vivas a su hermano Bartolomé de Vivas, en Cádiz', 'El licenciado y clérigo Rodrigo de Vivas informa brevemente a su hermano Bartolomé de Vivas del envío de cartas y dinero para él.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (703, 14, NULL, 'Fernandez60-MEX16-AVB-GHT-CCC', '391. De Leonor de Aguilera, casada con Francisco de Orozco, secretario de la audiencia de México, a su sobrino, Francisco del Castillo, en Atienza (Guadalajara), donde es regidor', 'Leonor de Aguilera escribe al marido de su sobrina, Francisco del Castillo, en respuesta a una suya, por la cual se alegra, explica que ella estuvo sirviendo en España a señores de los que no obtuvo mucha recompensa, le dice que ella puede ayudar a casar a sus hijos pues ella tenía uno que se murió por el camino.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (704, 14, NULL, 'Fernandez615-MEX16-VAG-AVB-CCC', '322. De Pedro del Castillo a su hijo, de idéntico nombre, en Torija (Guadalajara)', 'Pedro del Castillo pide a su hijo, de idéntico nombre, que vaya a América con su mujer y se lleve a su hermana.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (705, 14, NULL, 'Fernandez618-MEX16-VAG-AVB-CCC', '415. De Pedro Gómez de Montejo a su primo, el bachiller Pedro Ortiz, en Santaria de Ribarredonda', 'Pedro Gómez de Montejo pide a su primo, el bachiller Pedro Ortiz, con exceso de cortesía que haga lo posible para que dos hijos de su hermana se vayan con él.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (706, 14, NULL, 'Fernandez623-MEX16-VAG-AVB-CCC', '615. De Pedro Gómez de Montejo a Hernando Valenciano, platero de oro, en Madrid', 'Pedro Gómez pide a Hernando Valenciano que lleve la carta a su padre y hermanos para que sus sobrinos obtengan el permiso para poderse trasladar a su casa en la próxima flota.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (707, 14, NULL, 'Fernandez65-MEX16-AVB-GHT-CCC', '352. De Pedro Gómez de Montejo a su padre, Pedro Gómez de Montejo, en Frías (Burgos)', 'Pedro Gómez de Montejo expresa a su padre, Pedro Gómez de Montejo, la pena por no haber recibido carta suya, le pide que uno de sus sobrinos vaya con él y explica que ha enviado dinero para que pueda hacerse.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (708, 14, NULL, 'Fernandez66-MEX16-AVB-GHT-CCC', '618. De Juan Cabeza de Vaca a Elvira de Cantalejos, en Osuna (Sevilla)', 'Juan Cabeza de Vaca le dice a su hermana Elvira que le ha escrito tres cartas y que le ha mandado 100 pesos de plata para que vaya a verle y que se lleve algunos familiares más, que él les pagará los costes.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (709, 14, NULL, 'Fernandez67-MEX16-AVB-GHT-CCC', '623. De Juan Salcedo de Espinosa, maestro de construcción, a su yerno, Alonso de Arroyo, mercader en la Habana', 'Juan Salcedo le pide a su yerno Alonso de Arroyo que regrese a España por las grandes dificultades que está pasando y le ofrece su ayuda para así poder ver a su hija.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (710, 14, NULL, 'Fernandez68-MEX16-AVB-GHT-CCC', '88. De Francisco de Amor a su mujer, María de Frías, en Madrid', 'Francisco de Amor pide a su mujer, María de Frías, que se reúna con él en América.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (719, NULL, NULL, 'AGN_Indios_v006_exp044', NULL, NULL, NULL);
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (720, NULL, NULL, 'AGI_CONTRATACION_1223_N6', 'Registro del navío ''La Concepción de Mallorca''', 'Registro de ida de las mercancías del navío ''La Concepción de Mallorca'', maestre Diego Manuel, que salió como navío de registro con la flota del general Pedro Corbet, caballero de la Orden de Santiago, para Nueva España. Nota: Véase CONTRATACION,1224,N.1,R.7
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (721, NULL, NULL, 'ENL_Ancotitla_Jalisco_1652', 'Analcotitlan (Jalisco), 1652: Estate of Francisco Felipe', 'Además de inventariar los bienes de Francisco Felipe, se organizan y sufragan los gastos de su funeral, pero el énfasis y la motivación principal tienen que ver con el cobro de sus deudas con la cofradía y el altepetl.	
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (722, NULL, NULL, 'ENL_Azcapotzalco_Mexico_1703', 'Azcapotzalco (V. of Mexico), 1703: Land Dispute', 'La situación es que el español Andrés González se disputa ciertas tierras con los habitantes del distrito de San Simón (Pochtlan), la misma entidad donde se expidió el Doc. 5, el testamento de Angelina de 1695.				
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (723, NULL, NULL, 'ENL_Azcapotzalco_Mexico_1738', 'Azcapotzalco (V. of Mexico), 1738: Land Sale', 'Escritura de venta. Los documentos aquí reunidos representan un formidable esfuerzo de aculturación jurídica. Se sigue al pie de la letra un complejo protocolo de procedimientos españoles para la transferencia de tierras, y toda la terminología pertinente se maneja mediante traducciones ahora convencionales o mediante préstamos, incluida una frase técnica de préstamo como amparo de posesión, «afirmación o confirmación de posesión.»
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (724, NULL, NULL, 'ENL_Coyoacan_Region_1573', 'Coyoacan Region, 1573: Land Sale to a Spaniard', 'El manuscrito original se encuentra en AGN Tierras 1735, exp. 2, f. 122. Aquí dos hombres indígenas venden un pedazo de tierra a un español para pagar una misa para su padre.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (725, NULL, NULL, 'ENL_Coyoacan_Region_1575', 'Juan Alvaro sells or dontes land to church, COyoacan region, 1575', '«Juan Álvaro vende o dona tierras a la iglesia, región de Coyoacán, 1575», se afirma que las ventas directas a la iglesia eran raras, sin embargo, el siguiente documento es otra venta de este tipo. Sin embargo, al examinarlo de cerca, encontramos que los dos están relacionados, parte de una sola operación de los dominicos de Coyoacán. 
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (726, NULL, NULL, 'ENL_Coyoacan_Region_1575_Juan_Alvaro', 'Juan Alvaro sells land to the Dominican monastery, Coyoacan region, 1575. ', 'Venta de tierras. Vender tierras directamente a una iglesia era raro tanto para los españoles como para los indígenas, siendo las donaciones mucho más comunes y la más común de todas las donaciones de rentas de propiedades que permanecían en manos de laicos. En este caso, la casa y las tierras probablemente se encuentran cerca de la iglesia o de su estructura de apoyo inmediata y se utilizarán en el desarrollo de las instalaciones centrales de la orden dominica en Coyoacán (véase también Más allá de los códices, Doc. 21). La transacción es grande para los estándares indígenas y no pequeña para un intercambio de propiedad rural en la década de 1570.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (727, NULL, NULL, 'ENL_Coyoacan_Region_1575_Municipal_Land_Grant', 'Mercedes de tierras a Joaquín Flores de Atepotzco', 'Se conocen mercedes formales escritas de tierras dentro de entidades indígenas a lo largo de los siglos posteriores a la conquista, pero no son muy comunes. El presente ejemplo se asemeja bastante a una merced española del tipo más simple, pero la acción conjunta del grupo innominado de ciudadanos y/o autoridades del tlaxilacalli afectado es más típica de los procedimientos indígenas.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (728, NULL, NULL, 'ENL_Coyoacan_Region_1617', 'Coyoacan Region, 1617: Testament of Juan Fabián of San Bartolomé Atenco', 'Aquí tenemos un testamento rico en detalles e interés humano, así como expresión en primera persona. Juan Fabián representa al tipo de plebeyos que trabajaban como comerciantes provinciales, cuya fortuna a menudo estaba ligada a los españoles locales que podían proporcionarles crédito, una mula o alguna otra ventaja, como se ilustra en el testamento y los memorandos relacionados que aquí se presentan. 
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (729, NULL, NULL, 'ENL_Coyoacan_Region_1621', 'Coyoacan Region, 1621: Land Donation to Church of San Juan Bautista', 'Desconcertante y poco convencional en algunos aspectos, este documento al menos muestra claramente que el culto a los santos domésticos florecía en gran medida a principios de la tercera década del siglo XVII. La persona que produjo este texto da todos los indicios de dominar las convenciones de la escritura náhuatl de la época, pero después de dar la fecha de manera ejemplar, no identifica ni al donante ni a sí mismo como notario, ni al tlaxilacalli involucrado, y sólo sabemos que el escenario es Coyoacán por la mención de su iglesia principal de San Juan Bautista y el hecho de que el texto se conservó entre otros del gran Coyoacán. Que se trata de una donación de casas y tierras, y que es de carácter religioso, está fuera de toda duda. 
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (730, NULL, NULL, 'ENL_Coyoacan_1622', 'Coyoacan, 1622: Testament of don Juan de Guzmán', 'Testamento de Juan de Guzman		
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (731, NULL, NULL, 'ENL_Coyoacan_SXVI_Permisos_Juan_de_Guzman', 'Coyoacan, mid-16th c.: Perquisites of don Juan de Guzmán', 'Los documentos originales se encuentran en AGN Tierras 1735, exp. 2. Aquí se reúne un grupo de textos que van lejos para definir la posición de don Juan de Guzmán, tlatoani y gobernador de Coyoacán, a mediados del siglo XVI.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (272, 3, NULL, 'Amoxcalli_164', 'Reporte sobre el trabajo del padre Pichardo presentado a los fiscales de la Real Hacienda en 1812', NULL, NULL);
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (712, 14, NULL, 'Fernandez88-MEX16-AVB-GHT-CCC', '92. De Gaspar Viera a su mujer, Cecilia Rodríguez Verdugo, vecina de Sevilla', 'Gaspar Viera responde a una carta de su mujer, Jerónima de Loysa, y le pide que se reúna con él en América.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (713, 14, NULL, 'Fernandez8-MEX16-AVB-GHT-CCC', '417. De Ana Ruiz a su prima, Catalina de Pisa, en Almagro (Ciudad Real)', 'Ana Ruiz pide a su prima, Catalina de Pisa, que se reúna con ella en América para así no estar sola tras su viudez.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (714, 14, NULL, 'Fernandez92-MEX16-AVB-GHT-CCC', '94. De Gaspar Encinas a su mujer, María de Gaitán, vecina de Talavera de la Reina (Toledo), aunque la carta va a Triana (Sevilla)', 'Gaspar Encinas avisa a su mujer, María de Gaitán, del envío de dinero para viajar a América ella y sus hijos.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (715, 14, NULL, 'Fernandez94-MEX16-AVB-GHT-CCC', '97. De Juan Bravo de Salazar a su mujer, Catalina de Baeza, en Sevilla', 'Juan Bravo de Salazar insta a su mujer, Catalina de Baeza, a que viaje a América con él y le da instrucciones precisas para ello.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (716, 14, NULL, 'Fernandez97-MEX16-AVB-GHT-CCC', '102. De Bartolomé de Morales, barbero, a su mujer, Catalina de Ávila, vecina de Constantina (Sevilla)', 'Bartolomé de Morales, barbero, se excusa por no poder ir a España e insta a su mujer, Catalina de Ávila, a que viaje a América con él, para lo cual envía dinero y le da instrucciones precisas.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (717, 14, NULL, 'Fernandez9-MEX16-AVB-GHT-CCC', '60. De Marcos Rodríguez a su mujer, Catalina Martín, en Barcience (Toledo)', 'Marcos Rodríguez envía dinero a su mujer, Catalina Martín, para que realice el viaje a América.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (718, 15, NULL, 'Yamanday', NULL, NULL, NULL);
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (732, NULL, NULL, 'ENL_Cuernavaca_1559', 'Cuernavaca, 1559: Testament of don Toribio Cortés', 'El testamento de don Toribio Cortés llega a nuestros días gracias a una disputa de propiedad de principios del siglo XVIII que enfrentó al poseedor del ingenio azucarero de Santa Ana Amanalco con los líderes indígenas del pueblo de Cuernavaca. La urgencia de la situación llevó a los dirigentes nahuas de Cuernavaca de principios del siglo XVIII a presentar el texto en náhuatl y una traducción al español de finales del siglo XVII del testamento a las autoridades adjudicadoras como prueba de la legítima propiedad corporativa de la tierra. 
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (733, NULL, NULL, 'ENL_Cuernavaca_1579', 'Cuernavaca, 1579: Testament of don Juan Ximénez of Cuernavaca Tecpan', 'El testamento náhuatl dejado por el noble don Juan Ximénez se encuentra en los registros del Archivo General de la Nación de México, que datan de 1694. El litigio que en ellos se trata tiene que ver con el secuestro de los bienes y propiedades del descendiente de don Juan, don Antonio de Hinojosa.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (734, NULL, NULL, 'ENL_Cuernavaca_1607', 'Cuernavaca, 1607: Testament of doña María Ximénez', 'María, hija del señor nahua del siglo XVI don Juan Ximénez ha sobrevivido gracias a una supuesta malversación de fondos del tributo por parte de uno de sus descendientes. 
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (735, NULL, NULL, 'ENL_Guadalajara_1653', 'Guadalajara (Jalisco), 1653: Petition about Church of San Martín', 'El texto pertenece al género de las peticiones, junto con varios otros de esta colección, y en este caso se utiliza el préstamo español peticion como rótulo en lugar del equivalente náhuatl común tlaitlaniliztli. Breves fórmulas de petición hacen su aparición al principio y al final, pero el cuerpo, como la mayor parte del náhuatl occidental y, de hecho, la mayor parte del náhuatl periférico, está en un lenguaje muy realista. Es difícil saber si el náhuatl fue la primera lengua del escritor y de todo el grupo.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (736, NULL, NULL, 'ENL_Xalostotzitlan_1611', 'Jalostotitlan (Jalisco), 1611: Petition to Remove Priest', 'Peticiones de grupos indígenas que acusan al sacerdote local de mala conducta y piden su destitución. 
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (737, NULL, NULL, 'ENL_Metepec_1795', 'Metepec (Toluca), 1795: Testament of Miguel Jerónimo', 'Testamento de Miguel Jeronimo	
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (738, NULL, NULL, 'ENL_Pochtlan_1695', 'Pochtlan (Azcapotzalco), 1695: Testament of Angelina of San Simón Pochtlan', 'Testamento de Angelina de San Simon Pochtlan	
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (739, NULL, NULL, 'ENL_Tlatelolco_1823', 'Tlatelolco (Toluca), 1823: Testament of Margarita Feliciana', 'Testamento de Margarita Feliciana	
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (740, NULL, NULL, 'ENL_Tzacoalco_1629', 'Tzacoalco (Jalisco), 1629: concerns about a marriage', 'La entidad que genera la carta, San Francisco Tzaqualco, parece ser un altepetl de buen tamaño, con dos alcaldes, cinco regidores y un notario, aunque ninguno tiene el título de don, y falta un gobernador. El tema tiene que ver con una pareja que quiere casarse, siendo el hombre originario de San Francisco Tzaqualco, donde está escrita la carta, y la mujer de San Felipe [¿Xoquiyotl?].
