INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (746, NULL, NULL, 'AGI_GUADALAJARA_230_L1_f283r-283v', 'Barcas para el transporte entre Michoacán y Nueva Galicia', 'Real Cédula al presidente de la Audiencia de Guadalajara para que informe de la relación que ha hecho Melchor de Álava, vecino de Llerena, para que se le haga merced de poner dos barcas en dos ríos en los términos de los pueblos de Ciseo [Cuitzeo] y Echiconasatengo [La Barca], para el paso de bastimentos entre Michoacán y Nueva Galicia.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (747, NULL, NULL, 'AGI_CONTRATACION_1091_N12', 'Registro del navío: ''''San Antonio''''', 'Registro de ida del patache ''San Antonio'', maestre Juan Home, que salió de Cádiz, con la Flota de Antonio Navarro de Prado, para Nueva España.
