INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (751, NULL, NULL, 'NB_AyerCol_Ms1485_Sahagun_Sermonario_Mexicano', 'Siguense unos sermones de dominicas y de sanctos en lengua mexicana', 'El manuscrito es un semonario, parte de los documentos escritos por Bernardino de Sahagun y los intelectuales Nahuas que participaron en su trabajo. Los  los sermones se redactaron por primera vez en el año de 1540; pero esa primera redacción hoy se encuentra perdida. El Ms. 1485 de la Col. Ayer es una copia más tardía de aquella primera redacción, cuya elaboración data de 1548 y que fue corregida muchos años después por fray Bernardino, en 1563.	
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (752, NULL, NULL, 'LoC_Ed_Historia_Tolteca_Chichimeca', 'Historia Tolteca Chichimeca', 'El documento describe la historia de los Toltecas y Chichimecas desde la migracion Chichimeca hasta 1544			
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (753, NULL, NULL, 'AGN_HospJesus_c474_leg267-2_exp24', NULL, NULL, NULL);
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (754, NULL, NULL, 'LoC_Ed_Anales_de_Tecamachalco', 'Anales de Tecamachalco', 'Códices. Anales de Tecamachalco (Códice indígena, 1399-1590), archivado como Ms. G2, es una cronología náhuatl de los acontecimientos de 1399 a 1590. Fragmento de manuscrito azteca, 1520 (G8 Ms.), escrito en español sobre papel nativo, es un relato ilustrado de la conquista de México por Hernán Cortés. Libro códice del tributo (G24 Ms.) es un mapa que representa parcelas de tierra; incluye medidas, signos de lugar y topónimos. Escrito en jeroglíficos aztecas con ocasionales palabras en náhuatl, es el tercer fragmento del Códice de las posesiones de Don Andrés y data del siglo XVI. Códice indígena, libro de tributos (G30 Ms.), fechado hacia 1550, es un registro pictórico, en jeroglíficos aztecas y pictogramas con texto en español, de los pagos de tributos por los barrios de la ciudad de México. Códice indígena, 1564-1565 (G42 Ms.), en texto náhuatl con símbolos monetarios y ocasionales palabras en español, consiste en recibos de pagos a funcionarios indios del gobierno indígena de México-Tenochtitlán. Pintura del pueblo de Tecpatepec (Registro de gastos llevado por un escribano indio), fechado hacia 1570 y archivado como G71 Ms., representa en dibujos gastos pagados a funcionarios españoles. Los dibujos van acompañados de texto en español y algunas líneas en náhuatl.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (755, NULL, NULL, 'LoC_Ed_Libro_de_los_Guardianes_Cuauhtinchan', 'Libro de los Guardianes y Gobernados que fueron de este pueblo de San Juan Baptista Huatinchan de 1519 y hasta 1620 anos', '1519-1640		
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (756, NULL, NULL, 'LoC_Ed_Codice_Chimalpahin', 'Codice Chimalpahin', NULL, NULL);
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (757, NULL, NULL, 'AGN_Californias_col63_exp39_f342-349v', 'Título de un sitio y un solar en el barrio de San Pablo y declaración de que pertenecen al indio Sebastián Antonio de la Cruz, cacique del barrio de San Siprián Ometotititlán, jurisdicción de la parroquia de San Pablo', 'Título de un sitio y un solar en el barrio de San Pablo y declaración de que pertenecen al indio Sebastián Antonio de la Cruz, cacique del barrio de San Siprián Ometotititlán, jurisdicción de la parroquia de San Pablo. Ciudad de México. Un documento en nahuatl.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (758, NULL, NULL, 'LoC_Ed_The_book_of_tributes', 'MNAH_Archivo_Historico_Coleccion_Antigua_vol_549', 'Censos de Morelos ubicados en el Museo Nacional de Antropologia e Historia. Corresponde a las numeraciones casa por casa de las comunidades de Huitzillan y Quauhchichinollan		
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (759, NULL, NULL, 'NB_AyerCol_Ms1486_26_Admonitions', 'Siguense veynte y seis addiciones desta postilla', 'Este manuscrito es una fuente primaria clave para comprender la interpretación que Sahagún hizo del cristianismo para su público nahua. Contiene un texto bilingüe de las «Addiciones», adiciones escritas por Sahagún para complementar la «Postilla», o comentarios de las escrituras, utilizados en la labor misionera entre los aztecas y los nahuas. Las adiciones explican las tres virtudes cristianas de la fe, la esperanza y la caridad, siendo la caridad la que recibe un tratamiento más extenso. Los tres últimos capítulos describen los castigos del infierno, la recompensa de la virtud en las glorias del cielo, la muerte y el día del Juicio Final. También hay un fragmento de texto que contiene tenonotzaliztli (admoniciones morales y doctrinales) que condenan los rituales nativos. Un apéndice copiado por uno de los escribas de Sahagún, Alonso Vegerano, también condena las creencias religiosas indígenas, con especial énfasis en el papel del diablo en la vida indígena.		
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (760, NULL, NULL, 'NB_AyerCol_Ms1484_Ejercicios_Lengua_Mexicana', 'Comienc̨a un exercicio en lengua mexicana sacado del Sancto Evango', 'El volumen que aquí se presenta es una copia manuscrita contemporánea de la corrección y reelaboración que Sahagún hizo en 1574 de una compilación anónima de lecturas y meditaciones bíblicas en lengua náhuatl, parte de su «Postilla», o comentarios bíblicos, utilizados en su labor misionera entre los aztecas y los nahuas. Una sección introductoria de cinco páginas va seguida de meditaciones basadas en lecturas de los Evangelios para cada día de la semana. Los temas de las lecturas incluyen el anuncio del ángel del nacimiento de Cristo a los pastores; el joven Jesús enseñando a los ancianos en el templo; y Cristo estableciendo el sacramento de la Sagrada Comunión. La meditación trilingüe sobre la Eucaristía contiene la liturgia en latín, seguida de glosas en español y explicaciones en náhuatl sobre la ceremonia y su significado. Es una fuente primaria clave para comprender la interpretación que Sahagún hizo del cristianismo y de la liturgia católica romana para su público nahua.		
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (761, NULL, NULL, NULL, NULL, NULL, NULL);
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (1, 1, NULL, 'HPKraus_001', 'Royal cedula to the audencia of the Island of Española', '''- The judges are commanded to permit Francisco de Carrión, free-holder of Burgos, to bring away from the island Francisco, the nine-year-old son of his dead brother Hernando de Carrión and of an Indian woman, so that the petitioner may rear the boy as his own son and give him a Christian education in Spain.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (7, 1, NULL, 'HPKraus_104', 'Viceregal order', '''- The citizens of Los Valles had informed the Viceroy that the area was being depopulated because the beneficed secular priest who had been appointed for the town would not remain, and frequently the Spaniards were left without the sacraments. The Indians had departed altogether. The citizens had asked for Franciscan friars in place of the secular clergy to remedy the problem. The Viceroy sent an order to Captain Pero Martínez de Loaysa, alcalde mayor who resided in the town, to report on the various points of the petition. On the basis of the alcalde''s report and the fact that no secular priest had accepted the position, the Viceroy decided it would be better to put the friars in charge of the church for the good of both Spaniards and Indians. The town, being the only Spanish settlement in the region, was necessary for its defense; it was thought the Franciscans would attract the vecinos back and would help to pacify and settle the Indians. The presence of other Franciscans in the region would be a help to the new friars. Therefore, the Viceroy requests the Franciscan superior (custodio) of Tampico to assign to the town enough religious to instruct the people and to administer the sacraments. They will be responsible for the spiritual needs of the people just as the last beneficed clergyman was, and the people are to give their support. This arrangement is to be in effect until changed by the King or Viceroy. A report is to be sent regarding the fulfillment of the order.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (47, 1, NULL, 'HPKraus_142', 'Relazion De todo lo suçedido En la Jornada de omagua que por otro nombre es el dorado desde que fue encargada a Pedro de Orsua Por el marques de canete . . . y de como el cruel Tirano Lope de Aguirre llegó a las isla [sic] de la margarita y de las cruelda', '''- Provenance: Sir Thomas Phillipps and R. L. Harmsworth collections. This is an anonymous narrative of the same historical episode as recounted in the previous item. It seems to be an independent account, although both narratives contain versions of Lope de Aguirre''s letters to the provincial Montesinos and to Philip II of Spain. Even though the two accounts agree in many details, it is difficult to find a verbal dependence.
