INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (762, 3, NULL, 'Amoxcalli_035_036', 'Codice Aubin. Historia de la Nacion Mexicana. Codice de 1575', 'El Códice Aubin de 1576 original formó parte de la colección de Lorenzo Boturini Benaducci (1702-1749) y relata los acontecimientos hasta el año de 1606, actualmente se encuentra el la Biblioteca del Departamento Etnológico del Museo Británico ( Trustees of the British Museum) en Londres, Inglaterra y relata los hechos hasta 1606.
