INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (770, NULL, NULL, 'AGN_Mercedes_vol84segundaparte_exp238_fs100-100v', 'Instrucción que dio el virrey, don Luis de Velasco, para que la justicia del puerto de Veracruz encarcele a Manuel Ortiz, marinero de la caballería de las indias, a su esposa Agustina Carbajal y a los soldados implicados en la querella. El proceso fue iniciado por la relación que presentó Angelina Guebara, india natural del pueblo de Chachula, quien fue raptada por Manuel Ortiz por medio de amenazas, y obligada a cometer excesos carnales, estando siempre desnuda y descalza. Narra que no le curaba sus enfermedades, ni le enseñó cosas de virtud y la tenía en amancebamiento. Contiene testimonio de como fue recogida durante 10 meses por Francisca Osorio, mujer casada, siendo en una noche entraron 8 soldados a su casa, raptaron a Angelina Guebara y el almirante Juan Flores Ravanal abusó de Francisca Osorio, fue así como Manuel Ortiz se la llevó al puerto de Alvarado y de ahí al pueblo de Casamaloapa con una caja de ropa de Francisca Osorio en donde siguió sufriendo agravios.', 'Instrucción que dio el virrey, don Luis de Velasco, para que la justicia del puerto de Veracruz encarcele a Manuel Ortiz, marinero de la caballería de las indias, a su esposa Agustina Carbajal y a los soldados implicados en la querella. El proceso fue iniciado por la relación que presentó Angelina Guebara, india natural del pueblo de Chachula, quien fue raptada por Manuel Ortiz por medio de amenazas, y obligada a cometer excesos carnales, estando siempre desnuda y descalza. Narra que no le curaba sus enfermedades, ni le enseñó cosas de virtud y la tenía en amancebamiento. Contiene testimonio de como fue recogida durante 10 meses por Francisca Osorio, mujer casada, siendo en una noche entraron 8 soldados a su casa, raptaron a Angelina Guebara y el almirante Juan Flores Ravanal abusó de Francisca Osorio, fue así como Manuel Ortiz se la llevó al puerto de Alvarado y de ahí al pueblo de Casamaloapa con una caja de ropa de Francisca Osorio en donde siguió sufriendo agravios.
