INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (793, NULL, NULL, 'El Paraguay colonial, ¿una isla rodeada de tierra?', 'El Paraguay colonial, ¿una isla rodeada de tierra? Movimientos transcontinentales y transoceánicos en la ciudad de Asunción (siglos XVI-XVII)', 'This article challenges the prevailing notion that colonial Paraguay was an isolated "island surrounded by land" disconnected from the rest of the Spanish empire and world. Through an examination of archival documents from Paraguay 16th and 17th century, the article unveils the region''s surprising ethnic, cultural, and linguistic diversity. Case studies are presented of Africans, Afro-descendants, indigenous people from across the Americas, as well as Europeans of diverse origins (English, Italian, Greek, French, German) who found their way to Asuncion and this supposed frontier backwater. Their mobility, displacement, and connections across the Spanish Empire are traced through legal records, letters, testaments, and judicial cases. The experiences of individuals like the revolt of a maroon leader Diego Bretón, the Greek carpenter Estamate Cámara, the French gunpowder maker Julián, or the German soldier Ulrich Schmidl belie any notion of an insular, monocultural Paraguay in this era. Far from the mythical Hispanic-Guarani society, this paper paints a pluralistic colonial society immersed in transatlantic and transcontinental movements of peoples and information flows. Rethinking Paraguay''s past from long-neglected primary sources promises to shatter lingering historiographical biases portraying it as a stagnant historical isolate adrift from the broader currents of the early modern world.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (79, 1, NULL, 'HPKraus_148/09', 'Promotion for Pedro de Céspedes Vallejo', '''- Pedro de San Martín was giving up his position of adjutant of the presidio of San Agustín. Espinosa appoints Pedro de Céspedes Vallejo, alférez of Captain Melchor de Orantes, to take San Martín''s place. Signed, with seal intact.
