INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (451, 3, NULL, 'Amoxcalli_368', 'Arte de la lengua Hegue por el padre Balthasar de loaysa de la compañía de Jesús', NULL, NULL);
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (745, 4, NULL, 'AGI_CONTRATACION_1154A_N1_R2', 'Registro del navío: ''''San Sebastian''''', 'Registro de ida del navío ''San Sebastian'', maestre Pedro Díaz Franco, que salió, con la Flota de Juan Gutiérrez de Garibay, para Nueva España.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (156, 1, NULL, 'HPKraus_162', 'Report to the Secretary of State and of the Department of War', '''- No. 95 of Apodaca''s series. Subjects treated: the appearance of three supposed enemy vessels off the coast of San Blas (leaf 1); the departure of warships and troops to Monterey in California and reports from California (leaves 1-2); treaty of peace with Apaches at Tucson (leaf 2); the organization of a piratical force in Galveston to make raids in Tampico and Campeche (leaves 2-3); a description of the Yellowstone or Roche Jaune River made by Engineer Bartolomé Lafón (leaf 3); a flood in San Antonio, Tex., and assistance given to the town (leaves 3v-4); the arrival of silver from Chihuahua, Durango, El Rosario, Zacatecas, and Guadalajara (leaf 4); continued action by Colonel Matías Martín y Aguirre against the rebels in the Province of Valladolid (leaves 4-4v); surrender of Marshal Anaya (leaf 4v); action against Huerta, Cervantes, Guerrero, Bedolfa, Montesdoca, and other insurgents (leaves 4v-5); construction of fortifications at Puruándiro (leaf 5); actions of the division of Acapulco, especially against Guerrero''s men (leaves 5-6v); efforts to bring to submission the priest Izquierdo and his followers who had fortified themselves in the Peñas de San Pedro, Serranía de Goleta (leaves 6v-7v); a battle at Sultepec (leaf 7v); state of peace in localities along the road from Mexico City to Valladolid (leaves 7v-8); actions of the troops of the Province of Guanajuato, notably the killing of Andrés Delgado, alias El Giro (leaves 8-8v); resultant surrender of a number of insurgents (leaf 8v); expectation that the other rebels in the Bajío will request amnesty (leaf 9); actions of the division of Querétaro (leaf 9-9v), state of peace along the road to Querétaro, in the military sector of Apan and in the Provinces of Puebla, Oaxaca, and most of Veracruz (leaves 9v-10); the daily service of pack trains from Veracruz to other parts of the realm (leaves 10-10v); income to the royal treasury (leaves 10v-11), memorial ceremonies for the deceased wife of King Ferdinand VII, Queen María Isabel Francisca de Braganza y de Borbón (leaf 11); and the issuance of 188 letters of amnesty during the present month (leaves 11-11v). Signed.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (157, 1, NULL, 'HPKraus_162/2', 'Report to the Secretary of State and of the Department of War', '''- No. 99 of Apodaca''s series. Subjects treated: anchoring in San Blas harbor of three foreign ships, the Anglo-American ship The Two Catharines ("Las dos Catalinas") on July 9, the English whaler Wander on July 13, and the United States warship Macedonia with 300 men on July 19 and the resultant concern of José de la Cruz, commandant general of New Galicia (leaves 1-2v); previous appearance of the Macedonia in Acapulco and anticipation that it would return (leaves 2v-3); refusal of the request of a German passenger of the Macedonia , the "Varon de Kavanagk," to travel across Mexico (leaf 3); sighting of a boat off San Blas on July 8, 16, 17, and 19, suspected of being the insurgent boat La Chilena (leaf 3); departure of the brigantine Kosak from San Blas for Upper California on July 15 with 100 soldiers (leaves 3-3v); agreement of peace among Apache groups at Tucson (leaf 4); state of peace in the Interior Provinces (leaves 4-4v); threat of an invasion of Texas by adventurers from the United States under Lallemand and preparation for defense by the Viceroy (leaves 4v-8); the policy of the United States in assisting the insurgents (leaves 8-8v); request for more troops (leaves 8v-9); peace in Zacatecas and San Luis Potosí and arrival of silver shipments and livestock from there (leaf 9); actions in Guanajuato and the "tierra fría" around Valladolid and grants of amnesty to many, including Licenciado Mariano and José María Huerta (leaves 9-10); actions in the south against Guerrero and his supporters (leaves 10-10v); continued resistance of rebels at La Goleta (leaves 10v-11); continued peace along the highway from Mexico City to Valladolid (leaf 11); further actions in Guanajuato (leaves 11-12); amnesty accepted by José Antonio Magos and Cristóbal Mejía with their followers in the Sierra Gorda (leaves 12-13); description of the Sierra Gorda (leaf 13); recommendations and promotions for those involved in the campaign of the Sierra Gorda (leaves 13-14v); proposed action against the Sierra de Jalpa (leaf 14v); peace along the road from Mexico City to Querétaro, in the region of Apan and in Puebla, Oaxaca, and Veracruz (leaves 14v-15v); resumption of commerce along the highways (leaves 15v-16); change of command at Veracruz (leaves 16-16v); departure of a convoy of silver and goods for Veracruz on August 6 (leaf 16v); reconstruction of the bridge at San Martin Texmelucan and of the inn at Córdoba (leaves 16v-17); improved military training at Monterrey, capital of the Interior Provinces (leaves 17-17v); income to the royal treasury (leaves 17v-18); and issuance of 742 letters of amnesty during the present month (leaf 18). Signed.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (160, 1, NULL, 'HPKraus_162/5', 'Report to the Secretary of State and of the Department of War', '''- No. 104 in Apodaca''s series. Subjects treated: sighting of an unidentified ship off the Punto de Tabo (leaf 1); anchoring of two foreign ships in San Blas harbor on November 16, the one an English vessel Hydra , the other an Anglo-American vessel Triton —both on whaling expeditions (leaves 1–1v); defensive preparations against the possibility of an attack on New Mexico by the previously mentioned Anglo-American expedition from St. Louis to the Yellowstone River (leaves 1v–4v); request for more troops (leaf 4v); preparations for an attack against the Anglo-American adventurers in Nacogdoches and report of an agreement between their leader James Long and the pirates in Galveston, also a report of an agreement between Luis de Onís, Spanish minister to the United States, and Swiss businessmen, allowing them to colonize 20 square leagues in Texas with Swiss and German colonists (leaves 4v–6); negotiations with Mariano Renovales (leaves 6–6v); shipment of silver from Chihuahua, Durango, and El Rosario (leaf 6v); peace in Zacatecas and San Luis Potosí and a silver shipment from the former (leaf 6v); actions of the Division of Guadalajara in the Province of Guanajuato, driving some of the Ortiz faction out of the area (leaves 6ví7); actions in highland Michoacán (leaves 7–8); and in lowland Michoacán, resulting in many requests for amnesty (leaf 8); defense of the Pacific coast in the region of Zacatula (leaves 8–8v); two weekly convoys from the area of Acapulco (leaf 8v); an encounter with Guerrero near the Hacienda of Canario in the province of Michoacán in which a number of the insurgent officers were captured or killed (leaves 8v–9); continued peace along the road to Valladolid (leaf 9); action against the remnants of the insurgent force from La Goleta (leaves 9–9v); actions in the Bajío of Guanajuato and Sierra de Jalpa (leaves 9v–10v); actions against the Ortizes in the Sierra de Guanajuato (leaf 10v); shipment of silver from Guanajuato (leaf 10v); destruction of resistance in the Sierra de Jalpa (leaves 10v–11); amnesties in Querétaro (leaf 11); peace along the highway to Querétaro, in the military district of Apan and in the Provinces of Puebla, Oaxaca, and Veracruz (leaves 11–12); income to the royal treasury (leaf 12); 1,172 letters of amnesty granted during the present month (leaves 12–12v); the extent of his line of military operations and the exposure of the realm to external attack (leaf 12v). Signed.
INSERT INTO public."Documents" (doc_id, inst_coll_proj_id, digitalizo_collab_id, document_internal_id, title, description, transcribio_collab_id) VALUES (167, 1, NULL, 'HPKraus_076', 'Copy of a royal cedula to Martín Enríquez, Viceroy of New Spain, or to his substitute in his absence', '''- The provincial of the Augustinian Order had informed the King that in their friary in Mexico City there were generally about 100 friars, with novices and students of the arts and theology. He suggests that it would be very helpful if another friary could be founded in the city where students could study better and practice the Indian language, administering the sacraments and preaching to the natives. For this purpose the church of San Pablo would be very good because in that section of the city there was no other church, and it was served by only one paid clergyman who was changed at the will of the archbishop and cathedral chapter. After the matter had been considered by the Council of the Indies, in consultation with the King, the present cedula was issued, commanding the Viceroy to meet with the archbishop and provincial to decide what should be done and to put it into effect, sending a report to the King. On the verso is the record of the Viceroy''s action regarding the cedula on July 27, 1575. He summoned the archbishop and the provincial of the Augustinians, Alonso de la Vera Cruz, and in their conference the archbishop opposed the transfer of the church to the Augustinians, while the provincial argued in favor of it, asserting that the natives would be given better care. The Viceroy sided with the provincial and commanded the archbishop to remove the secular priests from the church and turn it over to the Augustinians, instructing the friars at the same time to carry out what they had promised. Juan de la Cueva signed as official witness.
